"use strict";(self.webpackChunkwangdoc=self.webpackChunkwangdoc||[]).push([[7241],{64256:(n,s,a)=>{a.r(s),a.d(s,{data:()=>p});const p={key:"v-c6afb660",path:"/git-tutorial/operations.html",title:"Git的操作",lang:"zh-CN",frontmatter:{summary:"Git的操作 新建代码库 配置 Git的设置文件为.gitconfig，它可以在用户主目录下，也可以在项目目录下。 增加/删除文件 代码提交 分支 标签 查看信息 远程同步 撤销 其他 （完）",head:[["meta",{property:"og:url",content:"https://yzqbooks.github.io/wangdoc/wangdoc/git-tutorial/operations.html"}],["meta",{property:"og:site_name",content:"wangdoc"}],["meta",{property:"og:title",content:"Git的操作"}],["meta",{property:"og:type",content:"article"}],["meta",{property:"og:updated_time",content:"2022-04-06T10:09:00.000Z"}],["meta",{property:"og:locale",content:"zh-CN"}],["meta",{property:"article:modified_time",content:"2022-04-06T10:09:00.000Z"}]]},excerpt:"",headers:[{level:2,title:"新建代码库",slug:"新建代码库",children:[]},{level:2,title:"配置",slug:"配置",children:[]},{level:2,title:"增加/删除文件",slug:"增加-删除文件",children:[]},{level:2,title:"代码提交",slug:"代码提交",children:[]},{level:2,title:"分支",slug:"分支",children:[]},{level:2,title:"标签",slug:"标签",children:[]},{level:2,title:"查看信息",slug:"查看信息",children:[]},{level:2,title:"远程同步",slug:"远程同步",children:[]},{level:2,title:"撤销",slug:"撤销",children:[]},{level:2,title:"其他",slug:"其他",children:[]}],git:{createdTime:164923974e4,updatedTime:164923974e4,contributors:[{name:"yzqdev",email:"yzqdev@outlook.com",commits:1}]},readingTime:{minutes:4.46,words:1338},filePathRelative:"git-tutorial/operations.md"}},64234:(n,s,a)=>{a.r(s),a.d(s,{default:()=>t});const p=(0,a(66252).uE)('<h1 id="git的操作" tabindex="-1"><a class="header-anchor" href="#git的操作" aria-hidden="true">#</a> Git的操作</h1><h2 id="新建代码库" tabindex="-1"><a class="header-anchor" href="#新建代码库" aria-hidden="true">#</a> 新建代码库</h2><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token comment"># 在当前目录新建一个Git代码库</span>\n$ <span class="token function">git</span> init\n\n<span class="token comment"># 新建一个目录，将其初始化为Git代码库</span>\n$ <span class="token function">git</span> init <span class="token punctuation">[</span>project-name<span class="token punctuation">]</span>\n\n<span class="token comment"># 下载一个项目和它的整个代码历史</span>\n$ <span class="token function">git</span> clone <span class="token punctuation">[</span>url<span class="token punctuation">]</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h2 id="配置" tabindex="-1"><a class="header-anchor" href="#配置" aria-hidden="true">#</a> 配置</h2><p>Git的设置文件为<code>.gitconfig</code>，它可以在用户主目录下，也可以在项目目录下。</p><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token comment"># 显示当前的Git配置</span>\n$ <span class="token function">git</span> config --list\n\n<span class="token comment"># 编辑Git配置文件</span>\n$ <span class="token function">git</span> config -e <span class="token punctuation">[</span>--global<span class="token punctuation">]</span>\n\n<span class="token comment"># 设置提交代码时的用户信息</span>\n$ <span class="token function">git</span> config <span class="token punctuation">[</span>--global<span class="token punctuation">]</span> user.name <span class="token string">&quot;[name]&quot;</span>\n$ <span class="token function">git</span> config <span class="token punctuation">[</span>--global<span class="token punctuation">]</span> user.email <span class="token string">&quot;[email address]&quot;</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><h2 id="增加-删除文件" tabindex="-1"><a class="header-anchor" href="#增加-删除文件" aria-hidden="true">#</a> 增加/删除文件</h2><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token comment"># 添加指定文件到暂存区</span>\n$ <span class="token function">git</span> <span class="token function">add</span> <span class="token punctuation">[</span>file1<span class="token punctuation">]</span> <span class="token punctuation">[</span>file2<span class="token punctuation">]</span> <span class="token punctuation">..</span>.\n\n<span class="token comment"># 添加指定目录到暂存区，包括子目录</span>\n$ <span class="token function">git</span> <span class="token function">add</span> <span class="token punctuation">[</span>dir<span class="token punctuation">]</span>\n\n<span class="token comment"># 添加当前目录的所有文件到暂存区</span>\n$ <span class="token function">git</span> <span class="token function">add</span> <span class="token builtin class-name">.</span>\n\n<span class="token comment"># 删除工作区文件，并且将这次删除放入暂存区</span>\n$ <span class="token function">git</span> <span class="token function">rm</span> <span class="token punctuation">[</span>file1<span class="token punctuation">]</span> <span class="token punctuation">[</span>file2<span class="token punctuation">]</span> <span class="token punctuation">..</span>.\n\n<span class="token comment"># 停止追踪指定文件，但该文件会保留在工作区</span>\n$ <span class="token function">git</span> <span class="token function">rm</span> --cached <span class="token punctuation">[</span>file<span class="token punctuation">]</span>\n\n<span class="token comment"># 改名文件，并且将这个改名放入暂存区</span>\n$ <span class="token function">git</span> <span class="token function">mv</span> <span class="token punctuation">[</span>file-original<span class="token punctuation">]</span> <span class="token punctuation">[</span>file-renamed<span class="token punctuation">]</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br></div></div><h2 id="代码提交" tabindex="-1"><a class="header-anchor" href="#代码提交" aria-hidden="true">#</a> 代码提交</h2><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token comment"># 提交暂存区到仓库区</span>\n$ <span class="token function">git</span> commit -m <span class="token punctuation">[</span>message<span class="token punctuation">]</span>\n\n<span class="token comment"># 提交暂存区的指定文件到仓库区</span>\n$ <span class="token function">git</span> commit <span class="token punctuation">[</span>file1<span class="token punctuation">]</span> <span class="token punctuation">[</span>file2<span class="token punctuation">]</span> <span class="token punctuation">..</span>. -m <span class="token punctuation">[</span>message<span class="token punctuation">]</span>\n\n<span class="token comment"># 提交工作区自上次commit之后的变化，直接到仓库区</span>\n$ <span class="token function">git</span> commit -a\n\n<span class="token comment"># 提交时显示所有diff信息</span>\n$ <span class="token function">git</span> commit -v\n\n<span class="token comment"># 使用一次新的commit，替代上一次提交</span>\n<span class="token comment"># 如果代码没有任何新变化，则用来改写上一次commit的提交信息</span>\n$ <span class="token function">git</span> commit --amend -m <span class="token punctuation">[</span>message<span class="token punctuation">]</span>\n\n<span class="token comment"># 重做上一次commit，并包括指定文件的新变化</span>\n$ <span class="token function">git</span> commit --amend <span class="token operator">&lt;</span>file<span class="token operator"><span class="token file-descriptor important">1</span>&gt;</span> <span class="token operator">&lt;</span>file<span class="token operator"><span class="token file-descriptor important">2</span>&gt;</span> <span class="token punctuation">..</span>.\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br></div></div><h2 id="分支" tabindex="-1"><a class="header-anchor" href="#分支" aria-hidden="true">#</a> 分支</h2><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token comment"># 列出所有本地分支</span>\n$ <span class="token function">git</span> branch\n\n<span class="token comment"># 列出所有远程分支</span>\n$ <span class="token function">git</span> branch -r\n\n<span class="token comment"># 列出所有本地分支和远程分支</span>\n$ <span class="token function">git</span> branch -a\n\n<span class="token comment"># 新建一个分支，但依然停留在当前分支</span>\n$ <span class="token function">git</span> branch <span class="token punctuation">[</span>branch-name<span class="token punctuation">]</span>\n\n<span class="token comment"># 新建一个分支，并切换到该分支</span>\n$ <span class="token function">git</span> checkout -b <span class="token punctuation">[</span>branch<span class="token punctuation">]</span>\n\n<span class="token comment"># 新建一个分支，指向指定commit</span>\n$ <span class="token function">git</span> branch <span class="token punctuation">[</span>branch<span class="token punctuation">]</span> <span class="token punctuation">[</span>commit<span class="token punctuation">]</span>\n\n<span class="token comment"># 新建一个分支，与指定的远程分支建立追踪关系</span>\n$ <span class="token function">git</span> branch --track <span class="token punctuation">[</span>branch<span class="token punctuation">]</span> <span class="token punctuation">[</span>remote-branch<span class="token punctuation">]</span>\n\n<span class="token comment"># 切换到指定分支，并更新工作区</span>\n$ <span class="token function">git</span> checkout <span class="token punctuation">[</span>branch-name<span class="token punctuation">]</span>\n\n<span class="token comment"># 建立追踪关系，在现有分支与指定的远程分支之间</span>\n$ <span class="token function">git</span> branch --set-upstream <span class="token punctuation">[</span>branch<span class="token punctuation">]</span> <span class="token punctuation">[</span>remote-branch<span class="token punctuation">]</span>\n\n<span class="token comment"># 合并指定分支到当前分支</span>\n$ <span class="token function">git</span> merge <span class="token punctuation">[</span>branch<span class="token punctuation">]</span>\n\n<span class="token comment"># 选择一个commit，合并进当前分支</span>\n$ <span class="token function">git</span> cherry-pick <span class="token punctuation">[</span>commit<span class="token punctuation">]</span>\n\n<span class="token comment"># 删除分支</span>\n$ <span class="token function">git</span> branch -d <span class="token punctuation">[</span>branch-name<span class="token punctuation">]</span>\n\n<span class="token comment"># 删除远程分支</span>\n$ <span class="token function">git</span> push origin --delete <span class="token operator">&lt;</span>branch-name<span class="token operator">&gt;</span>\n$ <span class="token function">git</span> branch -dr <span class="token operator">&lt;</span>remote/branch<span class="token operator">&gt;</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br><span class="line-number">29</span><br><span class="line-number">30</span><br><span class="line-number">31</span><br><span class="line-number">32</span><br><span class="line-number">33</span><br><span class="line-number">34</span><br><span class="line-number">35</span><br><span class="line-number">36</span><br><span class="line-number">37</span><br><span class="line-number">38</span><br><span class="line-number">39</span><br></div></div><h2 id="标签" tabindex="-1"><a class="header-anchor" href="#标签" aria-hidden="true">#</a> 标签</h2><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token comment"># 列出所有tag</span>\n$ <span class="token function">git</span> tag\n\n<span class="token comment"># 新建一个tag在当前commit</span>\n$ <span class="token function">git</span> tag <span class="token punctuation">[</span>tag<span class="token punctuation">]</span>\n\n<span class="token comment"># 新建一个tag在指定commit</span>\n$ <span class="token function">git</span> tag <span class="token punctuation">[</span>tag<span class="token punctuation">]</span> <span class="token punctuation">[</span>commit<span class="token punctuation">]</span>\n\n<span class="token comment"># 查看tag信息</span>\n$ <span class="token function">git</span> show <span class="token punctuation">[</span>tag<span class="token punctuation">]</span>\n\n<span class="token comment"># 提交指定tag</span>\n$ <span class="token function">git</span> push <span class="token punctuation">[</span>remote<span class="token punctuation">]</span> <span class="token punctuation">[</span>tag<span class="token punctuation">]</span>\n\n<span class="token comment"># 提交所有tag</span>\n$ <span class="token function">git</span> push <span class="token punctuation">[</span>remote<span class="token punctuation">]</span> --tags\n\n<span class="token comment"># 新建一个分支，指向某个tag</span>\n$ <span class="token function">git</span> checkout -b <span class="token punctuation">[</span>branch<span class="token punctuation">]</span> <span class="token punctuation">[</span>tag<span class="token punctuation">]</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br></div></div><h2 id="查看信息" tabindex="-1"><a class="header-anchor" href="#查看信息" aria-hidden="true">#</a> 查看信息</h2><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token comment"># 显示有变更的文件</span>\n$ <span class="token function">git</span> status\n\n<span class="token comment"># 显示当前分支的版本历史</span>\n$ <span class="token function">git</span> log\n\n<span class="token comment"># 显示commit历史，以及每次commit发生变更的文件</span>\n$ <span class="token function">git</span> log --stat\n\n<span class="token comment"># 显示某个文件的版本历史，包括文件改名</span>\n$ <span class="token function">git</span> log --follow <span class="token punctuation">[</span>file<span class="token punctuation">]</span>\n$ <span class="token function">git</span> whatchanged <span class="token punctuation">[</span>file<span class="token punctuation">]</span>\n\n<span class="token comment"># 显示指定文件相关的每一次diff</span>\n$ <span class="token function">git</span> log -p <span class="token punctuation">[</span>file<span class="token punctuation">]</span>\n\n<span class="token comment"># 显示指定文件是什么人在什么时间修改过</span>\n$ <span class="token function">git</span> blame <span class="token punctuation">[</span>file<span class="token punctuation">]</span>\n\n<span class="token comment"># 显示暂存区和工作区的差异</span>\n$ <span class="token function">git</span> <span class="token function">diff</span>\n\n<span class="token comment"># 显示暂存区和上一个commit的差异</span>\n$ <span class="token function">git</span> <span class="token function">diff</span> --cached <span class="token punctuation">[</span><span class="token operator">&lt;</span>file<span class="token operator">&gt;</span><span class="token punctuation">]</span>\n\n<span class="token comment"># 显示工作区与当前分支最新commit之间的差异</span>\n$ <span class="token function">git</span> <span class="token function">diff</span> HEAD\n\n<span class="token comment"># 显示两次提交之间的差异</span>\n$ <span class="token function">git</span> <span class="token function">diff</span> <span class="token punctuation">[</span>first-branch<span class="token punctuation">]</span><span class="token punctuation">..</span>.<span class="token punctuation">[</span>second-branch<span class="token punctuation">]</span>\n\n<span class="token comment"># 显示某次提交的元数据和内容变化</span>\n$ <span class="token function">git</span> show <span class="token punctuation">[</span>commit<span class="token punctuation">]</span>\n\n<span class="token comment"># 显示某次提交发生变化的文件</span>\n$ <span class="token function">git</span> show --name-only <span class="token punctuation">[</span>commit<span class="token punctuation">]</span>\n\n<span class="token comment"># 显示某次提交时，某个文件的内容</span>\n$ <span class="token function">git</span> show <span class="token punctuation">[</span>commit<span class="token punctuation">]</span>:<span class="token punctuation">[</span>filename<span class="token punctuation">]</span>\n\n<span class="token comment"># 显示当前分支的最近几次提交</span>\n$ <span class="token function">git</span> reflog\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br><span class="line-number">29</span><br><span class="line-number">30</span><br><span class="line-number">31</span><br><span class="line-number">32</span><br><span class="line-number">33</span><br><span class="line-number">34</span><br><span class="line-number">35</span><br><span class="line-number">36</span><br><span class="line-number">37</span><br><span class="line-number">38</span><br><span class="line-number">39</span><br><span class="line-number">40</span><br><span class="line-number">41</span><br><span class="line-number">42</span><br></div></div><h2 id="远程同步" tabindex="-1"><a class="header-anchor" href="#远程同步" aria-hidden="true">#</a> 远程同步</h2><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token comment"># 下载远程仓库的所有变动</span>\n$ <span class="token function">git</span> fetch <span class="token punctuation">[</span>remote<span class="token punctuation">]</span>\n\n<span class="token comment"># 显示所有远程仓库</span>\n$ <span class="token function">git</span> remote -v\n\n<span class="token comment"># 显示某个远程仓库的信息</span>\n$ <span class="token function">git</span> remote show <span class="token punctuation">[</span>remote<span class="token punctuation">]</span>\n\n<span class="token comment"># 增加一个新的远程仓库，并命名</span>\n$ <span class="token function">git</span> remote <span class="token function">add</span> <span class="token punctuation">[</span>shortname<span class="token punctuation">]</span> <span class="token punctuation">[</span>url<span class="token punctuation">]</span>\n\n<span class="token comment"># 取回远程仓库的变化，并与本地分支合并</span>\n$ <span class="token function">git</span> pull <span class="token punctuation">[</span>remote<span class="token punctuation">]</span> <span class="token punctuation">[</span>branch<span class="token punctuation">]</span>\n\n<span class="token comment"># 上传本地指定分支到远程仓库</span>\n$ <span class="token function">git</span> push <span class="token punctuation">[</span>remote<span class="token punctuation">]</span> <span class="token punctuation">[</span>branch<span class="token punctuation">]</span>\n\n<span class="token comment"># 强行推送当前分支到远程仓库，即使有冲突</span>\n$ <span class="token function">git</span> push <span class="token punctuation">[</span>remote<span class="token punctuation">]</span> --force\n\n<span class="token comment"># 推送所有分支到远程仓库</span>\n$ <span class="token function">git</span> push <span class="token punctuation">[</span>remote<span class="token punctuation">]</span> --all\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br></div></div><h2 id="撤销" tabindex="-1"><a class="header-anchor" href="#撤销" aria-hidden="true">#</a> 撤销</h2><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token comment"># 恢复暂存区的指定文件到工作区</span>\n$ <span class="token function">git</span> checkout <span class="token punctuation">[</span>file<span class="token punctuation">]</span>\n\n<span class="token comment"># 恢复某个commit的指定文件到工作区</span>\n$ <span class="token function">git</span> checkout <span class="token punctuation">[</span>commit<span class="token punctuation">]</span> <span class="token punctuation">[</span>file<span class="token punctuation">]</span>\n\n<span class="token comment"># 恢复上一个commit的所有文件到工作区</span>\n$ <span class="token function">git</span> checkout <span class="token builtin class-name">.</span>\n\n<span class="token comment"># 重置暂存区的指定文件，与上一次commit保持一致，但工作区不变</span>\n$ <span class="token function">git</span> reset <span class="token punctuation">[</span>file<span class="token punctuation">]</span>\n\n<span class="token comment"># 重置暂存区与工作区，与上一次commit保持一致</span>\n$ <span class="token function">git</span> reset --hard\n\n<span class="token comment"># 重置当前分支的指针为指定commit，同时重置暂存区，但工作区不变</span>\n$ <span class="token function">git</span> reset <span class="token punctuation">[</span>commit<span class="token punctuation">]</span>\n\n<span class="token comment"># 重置当前分支的HEAD为指定commit，同时重置暂存区和工作区，与指定commit一致</span>\n$ <span class="token function">git</span> reset --hard <span class="token punctuation">[</span>commit<span class="token punctuation">]</span>\n\n<span class="token comment"># 重置当前HEAD为指定commit，但保持暂存区和工作区不变</span>\n$ <span class="token function">git</span> reset --keep <span class="token punctuation">[</span>commit<span class="token punctuation">]</span>\n\n<span class="token comment"># 新建一个commit，用来撤销指定commit</span>\n<span class="token comment"># 后者的所有变化都将被前者抵消，并且应用到当前分支</span>\n$ <span class="token function">git</span> revert <span class="token punctuation">[</span>commit<span class="token punctuation">]</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br></div></div><h2 id="其他" tabindex="-1"><a class="header-anchor" href="#其他" aria-hidden="true">#</a> 其他</h2><div class="language-bash ext-sh line-numbers-mode"><pre class="language-bash"><code><span class="token comment"># 生成一个可供发布的压缩包</span>\n<span class="token comment"># git archive</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>（完）</p>',23),e={},t=(0,a(83744).Z)(e,[["render",function(n,s){return p}]])},83744:(n,s)=>{s.Z=(n,s)=>{const a=n.__vccOpts||n;for(const[n,p]of s)a[n]=p;return a}}}]);